import{C as n,o as e,c as l,a5 as i,E as h}from"./chunks/framework.CW28V7p_.js";const r=JSON.parse('{"title":"6. Shell mechanics","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/6-shell.md","filePath":"module-0/6-shell.md","lastUpdated":1780937944000}'),p={name:"module-0/6-shell.md"},c=Object.assign(p,{setup(d){const a={id:"m0-6-shell",title:"🧠 Mini-check: Shell mechanics",intro:"3 питання — фокус на тому що ламається у твоїх щоденних командах.",questions:[{type:"mcq",q:'Ти запускаєш sudo doublezero-solana shreds publisher-rewards configure ... і отримуєш "command not found". У звичайному (не-sudo) shell doublezero-solana працює. Чому (обери всі правдоподібні)?',options:["sudo resets PATH за замовчуванням, doublezero-solana не у secure_path","sudo вимагає absolute path до бінарника","Користувач root не має дозволу на цей binary","Binary потребує спеціального middleware"],correct:[0],explanation:'sudo за замовчуванням resets PATH до secure_path (/etc/sudoers config). Якщо твій binary у ~/.cargo/bin/ або іншому non-secure_path location — sudo його не знаходить. Fix варіанти: (1) sudo env "PATH=$PATH" doublezero-solana ..., (2) sudo /full/path/to/doublezero-solana ..., (3) sudo -i щоб стати root з повним shell.'},{type:"command",q:"Напиши команду яка покаже всю env variable PATH (де shell шукає бінарники).",accepts:["echo $PATH",'echo "$PATH"',"env | grep PATH","printenv PATH"],ideal:"echo $PATH",explanation:"echo $PATH виведе значення (типу /usr/local/bin:/usr/bin:/bin). env показує ВСІ env vars, можеш grep. printenv специфічно для env vars. Bash потребує prefix $ щоб expand variable у значення."},{type:"scenario",q:"Ти хочеш зберегти output довгої команди (solana validators) у файл І ОДНОЧАСНО бачити його у терміналі. Напиши command pipeline що це робить.",ideal:`solana validators | tee output.txt

Або з append: solana validators | tee -a output.txt

Як працює: pipe | передає stdout solana validators у stdin tee. Команда tee читає stdin і пише ОДНОЧАСНО у file І у stdout (тому ти бачиш на екрані). -a режим append (без -a перезаписує файл щоразу).

Якщо треба ще й stderr захопити: solana validators 2>&1 | tee output.txt — 2>&1 redirect stderr (file descriptor 2) у stdout (file descriptor 1), потім обидва йдуть у pipe.`,explanation:"Ключові поняття: pipe (|) передає stdout наступній команді, tee splits output у файл + stdout. Якщо ти описала tee + -a flag — повна відповідь. Bonus якщо знаєш про 2>&1 для combine stderr."}]};return(o,s)=>{const t=n("Quiz");return e(),l("div",null,[s[0]||(s[0]=i("",64)),h(t,{data:a}),s[1]||(s[1]=i("",6))])}}});export{r as __pageData,c as default};
